<?php
foreach ([__DIR__.'/../../app/bootstrap.php', '/var/www/appsbilling-commercial-platform/app/bootstrap.php'] as $boot) { if (is_file($boot)) { require_once $boot; break; } }
if (!function_exists('require_tenant_user')) { http_response_code(500); exit('Bootstrap tenant tidak ditemukan'); }
$u=require_tenant_user();
$tenant=q1('SELECT * FROM tenants WHERE id=?',[(int)$u['tenant_id']]);
if(!$tenant) { http_response_code(404); exit('Tenant tidak ditemukan'); }
$db=tenant_db_path($tenant);
provision_tenant_db($db,$tenant);
$pdo=new PDO('sqlite:'.$db);
$pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);
$pdo->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);
tenant_ensure_v3_core_schema($pdo);
$type=$_GET['type'] ?? 'receipt';
$id=(int)($_GET['id'] ?? 0);
function p_e($s){ return htmlspecialchars((string)$s,ENT_QUOTES,'UTF-8'); }
function p_money($n){ return 'Rp '.number_format((int)$n,0,',','.'); }
if($type!=='receipt'){ http_response_code(404); exit('Jenis cetak belum tersedia'); }
$st=$pdo->prepare("SELECT pay.*,c.customer_code,c.name customer_name,c.address,c.phone,c.pppoe_username,c.onu_name,pk.name package_name,pk.speed,inv.invoice_code,inv.amount invoice_amount,inv.discount_amount,inv.discount_note,inv.balance_amount,ba.bank_name,ba.account_number,ba.account_name,ba.label bank_label FROM payments pay JOIN customers c ON c.id=pay.customer_id LEFT JOIN packages pk ON pk.id=c.package_id LEFT JOIN invoices inv ON inv.id=pay.invoice_id LEFT JOIN bank_accounts ba ON ba.id=pay.bank_account_id WHERE pay.id=?");
$st->execute([$id]);
$r=$st->fetch();
if(!$r){ http_response_code(404); exit('Pembayaran tidak ditemukan'); }
$brand=($tenant['app_name'] ?? '') ?: (($tenant['company_name'] ?? '') ?: 'AppsBilling');
$company=($tenant['company_name'] ?? '') ?: 'PT Denta Sejahtera Group';
$logoPath=($tenant['receipt_logo_path'] ?? '') ?: ($tenant['app_logo_path'] ?? '');
if($logoPath!=='' && str_starts_with($logoPath,'/')) $logo=$logoPath;
elseif($logoPath!=='') $logo='/uploads/'.ltrim($logoPath,'/');
else $logo='/assets/dentanet-logo-20260715.jpg';
$period=$r['invoice_month'] ?: date('Y-m');
?><!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Bukti pembayaran <?=p_e($r['payment_code'])?></title><style>*{box-sizing:border-box}body{margin:0;background:#e5e7eb;color:#111827;font-family:Arial,Helvetica,sans-serif;font-size:12px}.actions{display:flex;justify-content:center;gap:8px;padding:14px}.actions button{border:0;border-radius:6px;padding:9px 14px;color:#fff;background:#374151;font-weight:700}.actions .primary{background:#0f5ea8}.paper{width:210mm;min-height:148mm;margin:0 auto 24px;background:#fff;padding:10mm 12mm;box-shadow:0 12px 34px rgba(15,23,42,.18)}.topline{display:grid;grid-template-columns:1fr 1fr 1fr;font-size:11px}.sys-title{text-align:center}.brand-row{display:grid;grid-template-columns:1fr 105px;gap:18px;margin-top:14px}.office{font-size:11px;line-height:1.35}.logo-wrap{text-align:right}.logo-wrap img{width:90px;max-height:70px;object-fit:contain}.rule{border:0;border-top:1px solid #222;margin:18px 0 0}.doc-title{text-align:center;font-size:27px;font-weight:400;color:#6b7280;margin:4px 0}.rule.thin{margin:0 0 12px}.grid{display:grid;grid-template-columns:105px 8px 1fr;max-width:620px;font-size:11px;line-height:1.35}.label{color:#6b7280;text-align:right}.items{width:100%;border-collapse:collapse;margin-top:24px}.items th{font-weight:400;color:#6b7280;text-align:left;border-bottom:1px solid #222;padding:0 8px 7px}.items td{padding:10px 8px;border-bottom:1px solid #ccc;vertical-align:top}.num{text-align:right;white-space:nowrap}.center{text-align:center}.summary{margin:12px 0 0 auto;width:320px}.summary div{display:flex;justify-content:space-between;padding:4px 0}.summary .grand{border-top:1px solid #111;margin-top:4px;padding-top:8px;font-size:15px}.note{margin-top:18px;color:#374151}.sign{margin-top:28px;text-align:right}.sign-space{height:42px}@media print{body{background:#fff}.actions{display:none}.paper{width:auto;min-height:0;margin:0;box-shadow:none;padding:6mm 8mm}@page{size:A4 portrait;margin:7mm}}</style></head><body><div class="actions"><button class="primary" onclick="window.print()">Cetak / Print</button><button onclick="history.back()">Kembali</button></div><main class="paper"><section class="topline"><div><?=p_e(date('d/m/Y H:i'))?></div><div class="sys-title">e-Billing · Tenant <?=p_e($tenant['account_no'] ?? '-')?></div><div></div></section><section class="brand-row"><div class="office"><b><?=p_e($brand)?></b><br><?=p_e($company)?><br>No Akun: <?=p_e($tenant['account_no'] ?? '-')?></div><div class="logo-wrap"><img src="<?=p_e($logo)?>" alt="Logo"></div></section><hr class="rule"><h1 class="doc-title">Bukti pembayaran</h1><hr class="rule thin"><section class="grid"><div class="label">No Bukti</div><div>:</div><div><b><?=p_e($r['payment_code'])?></b><?=!empty($r['invoice_code'])?' / '.p_e($r['invoice_code']):''?></div><div class="label">ID Pelanggan</div><div>:</div><div><?=p_e($r['customer_code'])?></div><div class="label">Nama</div><div>:</div><div><?=p_e($r['customer_name'])?></div><div class="label">Telepon</div><div>:</div><div><?=p_e($r['phone'] ?: '-')?></div><div class="label">Alamat</div><div>:</div><div><?=p_e($r['address'] ?: '-')?></div><div class="label">Account</div><div>:</div><div><?=p_e($r['pppoe_username'] ?: ($r['onu_name'] ?: '-'))?></div><div class="label">Metode</div><div>:</div><div><?=p_e($r['method'])?><?=tenant_bank_label($r)!==$r['method']?' · '.p_e(tenant_bank_label($r)):''?></div></section><table class="items"><thead><tr><th style="width:45px">No.</th><th>Nama pembayaran</th><th class="num">Tagihan</th><th class="num">Jumlah bayar</th><th class="center">Qty</th><th class="num">Total</th></tr></thead><tbody><tr><td>1</td><td><b><?=p_e(($r['package_name'] ?: 'Paket internet').' '.($r['speed'] ?: ''))?></b><br>Periode <?=p_e($period)?></td><td class="num"><?=p_money($r['invoice_amount'] ?: $r['amount'])?></td><td class="num"><?=p_money($r['amount'])?></td><td class="center">1</td><td class="num"><?=p_money($r['amount'])?></td></tr><?php if((int)$r['discount_amount']>0): ?><tr><td>2</td><td>Diskon / Potongan<br><small><?=p_e($r['discount_note'] ?: 'Potongan tagihan')?></small></td><td class="num">-<?=p_money($r['discount_amount'])?></td><td class="num">-<?=p_money($r['discount_amount'])?></td><td class="center">1</td><td class="num">-<?=p_money($r['discount_amount'])?></td></tr><?php endif; ?></tbody></table><section class="summary"><div><span>Subtotal bayar</span><b><?=p_money($r['amount'])?></b></div><div><span>Sisa tagihan</span><b><?=p_money($r['balance_amount'])?></b></div><div class="grand"><span>Status</span><b><?=((int)$r['balance_amount']<=0?'LUNAS':'SEBAGIAN')?></b></div></section><p class="note"><b>Catatan:</b> <?=p_e($r['notes'] ?: 'Pembayaran langganan pelanggan.')?></p><section class="sign"><div>Penerima</div><div class="sign-space"></div><b><?=p_e($r['received_by'] ?: ($u['name'] ?? 'Admin'))?></b></section></main></body></html>